#!/usr/bin/env bats

# Workflow-level tests. These exercise the GitHub Actions workflow via `act`.
# Every test case stages a fixture, runs `act push --rm`, captures output to
# act-result.txt (cumulative), and asserts on EXACT expected values.

WORKFLOW="${BATS_TEST_DIRNAME}/../.github/workflows/semantic-version-bumper.yml"
PROJECT_ROOT="${BATS_TEST_DIRNAME}/.."
ACT_RESULT="${PROJECT_ROOT}/act-result.txt"

setup_file() {
  : > "$ACT_RESULT"
}

@test "workflow YAML exists" {
  [ -f "$WORKFLOW" ]
}

@test "actionlint passes" {
  run actionlint "$WORKFLOW"
  [ "$status" -eq 0 ]
}

@test "workflow declares expected triggers" {
  grep -qE '^on:' "$WORKFLOW"
  grep -q 'push:'             "$WORKFLOW"
  grep -q 'pull_request:'     "$WORKFLOW"
  grep -q 'workflow_dispatch' "$WORKFLOW"
}

@test "workflow checks out repo and runs the script" {
  grep -q 'actions/checkout@v4' "$WORKFLOW"
  grep -q 'bump-version.sh'     "$WORKFLOW"
}

@test "workflow references files that exist" {
  [ -f "${PROJECT_ROOT}/bump-version.sh" ]
  [ -f "${PROJECT_ROOT}/tests/bump-version.bats" ]
  [ -d "${PROJECT_ROOT}/fixtures/feat" ]
}

# ----- act-driven cases -----
# Single act run drives all fixtures via env override (FIXTURE_DIR), keeping
# us under the 3-run cap. Each iteration appends to act-result.txt.

run_act_case() {
  local fixture="$1" expected="$2"
  cd "$PROJECT_ROOT"
  {
    echo "==================================================================="
    echo "FIXTURE: ${fixture}    EXPECTED: ${expected}"
    echo "==================================================================="
  } >> "$ACT_RESULT"
  # Pass FIXTURE_DIR via --env so the workflow's env: block picks it up.
  run act push --rm --env "FIXTURE_DIR=${fixture}"
  echo "$output" >> "$ACT_RESULT"
  echo "---- exit=$status ----" >> "$ACT_RESULT"
  [ "$status" -eq 0 ]
  [[ "$output" == *"NEW_VERSION=${expected}"* ]]
  [[ "$output" == *"Job succeeded"* ]]
}

@test "act: feat fixture bumps 1.2.3 -> 1.3.0" {
  run_act_case "feat" "1.3.0"
}

@test "act: fix fixture bumps 1.2.3 -> 1.2.4" {
  run_act_case "fix" "1.2.4"
}

@test "act: breaking fixture bumps 1.2.3 -> 2.0.0" {
  run_act_case "breaking" "2.0.0"
}

